#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>

namespace delete_inactive_users {

struct User {
  sqlgen::PrimaryKey<int> user_id;
  std::string username;
  std::optional<sqlgen::DateTime> last_login;
  std::string status = "active";
};

int delete_inactive_users() {
  using namespace sqlgen::literals;

  // Connect to the database
  auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");

  // Start transaction and perform deletion
  return conn_result
      .and_then([](auto conn) { return conn->begin_transaction(); })
      .and_then([](auto conn) {
          // Create delete query with where condition
          auto query = sqlgen::delete_from<User> 
                     | sqlgen::where("last_login"_c < "2025-01-01");
          return query(conn);
      })
      .and_then([](auto conn) { return conn->commit(); })
      .transform([](auto) { return 0; })  // Success: return 0
      .or_else([](auto error) { return -1; });  // Error: return -1
}

} // namespace delete_inactive_users
```

## Explanation:

