#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>

namespace mathematical_operations_analysis {

struct Product {
  sqlgen::PrimaryKey<int> product_id;
  std::string name;
  double price;
  int quantity;
  double discount_rate;
};

struct MathAnalysis {
  int product_id;
  std::string name;
  double abs_price;
  double ceil_price;
  double floor_price;
  double rounded_price;
  double exp_discount;
  double ln_price;
  double log2_quantity;
  double sin_discount;
  double cos_discount;
  double tan_discount;
  double sqrt_quantity;
};

/**
 * Insert products into a temporary SQLite table and run a SELECT that computes
 * various mathematical expressions, returning results as std::vector<MathAnalysis>.
 */
std::vector<MathAnalysis> analyze_mathematical_operations(const std::vector<Product>& products) {
  using namespace sqlgen::literals;

  // 1. Connect to SQLite database
  auto conn = sqlgen::sqlite::connect("test_db.sqlite").value();

  // 2. Create temporary table (if not exists)
  conn.execute("CREATE TEMPORARY TABLE IF NOT EXISTS Product ("
               "product_id INTEGER PRIMARY KEY, "
               "name VARCHAR(100) NOT NULL, "
               "price REAL NOT NULL, "
               "quantity INTEGER NOT NULL, "
               "discount_rate REAL NOT NULL)").value();

  // 3. Insert products into the table
  auto insert_query = sqlgen::insert(products);
  insert_query(conn).value();

  // 4. Build complex SELECT query with mathematical operations
  auto query = sqlgen::select<Product>(
    "product_id"_c,
    "name"_c,
    sqlgen::abs("price"_c) | sqlgen::as<"abs_price">,
    sqlgen::ceil("price"_c) | sqlgen::as<"ceil_price">,
    sqlgen::floor("price"_c) | sqlgen::as<"floor_price">,
    sqlgen::round("price"_c, 2) | sqlgen::as<"rounded_price">,
    sqlgen::exp("discount_rate"_c / 100) | sqlgen::as<"exp_discount">,
    sqlgen::ln("price"_c) | sqlgen::as<"ln_price">,
    sqlgen::log2("quantity"_c) | sqlgen::as<"log2_quantity">,
    sqlgen::sin("discount_rate"_c) | sqlgen::as<"sin_discount">,
    sqlgen::cos("discount_rate"_c) | sqlgen::as<"cos_discount">,
    sqlgen::tan("discount_rate"_c) | sqlgen::as<"tan_discount">,
    sqlgen::sqrt("quantity"_c) | sqlgen::as<"sqrt_quantity">
  ) | sqlgen::to<std::vector<MathAnalysis>>;

  // 5. Execute query and return results
  return query(conn).value();
}

}  // namespace mathematical_operations_analysis
```

## Key Implementation Points:

1. **Database Connection**: Uses `sqlgen::sqlite::connect()` to establish connection to "test_db.sqlite"

2. **Table Creation**: Creates a temporary table using `CREATE TEMPORARY TABLE IF NOT EXISTS` syntax

3. **Data Insertion**: Uses `sqlgen::insert()` to insert the product data into the table

4. **Complex Query Construction**: Builds a SELECT query with:
   - Column selection using string literals (`"product_id"_c`)
   - Mathematical operations: `abs()`, `ceil()`, `floor()`, `round()`
   - Exponential/logarithmic functions: `exp()`, `ln()`, `log2()`
   - Trigonometric functions: `sin()`, `cos()`, `tan()`
   - Square root: `sqrt()`
   - Field aliasing using `| sqlgen::as<"alias_name">`

5. **Result Mapping**: Uses `| sqlgen::to<std::vector<MathAnalysis>>` to map results to the target struct

6. **Execution**: Calls the query with the connection and returns the results

This implementation follows sqlgen's fluent API pattern and demonstrates proficiency with the library's mathematical operation functions as specified in the assessment objectives.

