  std::optional<std::string> department_name;
  std::optional<std::string> first_name;
  std::optional<std::string> last_name;
  std::optional<double> salary;
};

struct JoinAnalysis {
  std::vector<JoinResult> inner_join_results;
  std::vector<JoinResult> left_join_results;
  std::vector<JoinResult> right_join_results;
  std::vector<JoinResult> full_join_results;
};

JoinAnalysis analyze_department_employees_impl(const std::vector<Department>& depts, const std::vector<Employee>& emps) {
  // Create SQLite connection
  auto conn = sqlgen::sqlite::connect(":memory:");

  // Create temporary tables using write function
  write(depts)(conn);
  write(emps)(conn);

  // Define column references using literal operator
  using namespace sqlgen::literals;

  // Build and execute INNER JOIN query
  auto inner_query = select_from<Department, decltype(Department::department_name)>("department_name"_t1)
                   | inner_join<Employee, "e">("department_id"_t1 == "department_id"_t2)
                   | to<std::vector<JoinResult>>;

  // Build and execute LEFT JOIN query
  auto left_query = select_from<Employee, decltype(Employee::employee_id)>("first_name"_t2, "last_name"_t2, "salary"_t2)
                 | left_join<Department, "d">("department_id"_t2 == "department_id"_t1)
                 | to<std::vector<JoinResult>>;

  // Build and execute RIGHT JOIN query
  auto right_query = select_from<Employee, decltype(Employee::employee_id)>("first_name"_t2, "last_name"_t2, "salary"_t2)
                  | right_join<Department, "d">("department_id"_t2 == "department_id"_t1)
                  | to<std::vector<JoinResult>>;

  // Build and execute FULL JOIN query
  auto full_query = select_from<Employee, decltype(Employee::employee_id)>("first_name"_t2, "last_name"_t2, "salary"_t2)
                 | full_join<Department, "d">("department_id"_t2 == "department_id"_t1)
                 | to<std::vector<JoinResult>>;

  // Execute queries and populate results
  auto inner_result = inner_query(conn);
  auto left_result = left_query(conn);
  auto right_result = right_query(conn);
  auto full_result = full_query(conn);

  // Map results to JoinAnalysis structure
  JoinAnalysis analysis;
  analysis.inner_join_results = std::move(inner_result.value());
  analysis.left_join_results = std::move(left_result.value());
  analysis.right_join_results = std::move(right_result.value());
  analysis.full_join_results = std::move(full_result.value());

  return analysis;
}

}  // namespace analyze_department_employees
```

## Key Implementation Points:

1. **SQLite Connection**: Used `sqlgen::sqlite::connect()` to create an in-memory database connection
2. **Temporary Tables**: Used the `write` function to create temporary tables for both Department and Employee data
3. **Column References**: Utilized the literal operator `""_t1` and `""_t2` for table aliases as shown in the reference materials
4. **Query Building**: Constructed each join type using the appropriate sqlgen functions (`inner_join`, `left_join`, `right_join`, `full_join`)
5. **Result Mapping**: Converted query results to the required `JoinResult` and `JoinAnalysis` structures
6. **Error Handling**: Used `.value()` to extract results assuming successful execution (production code would need proper error handling)

The implementation follows the sqlgen library patterns demonstrated in the reference materials, particularly the use of the pipe operator `|` for query composition and the literal operators for column references.

